// This code has been generated by Claude.ai

const ACCOUNTS = [
  { instance: "gotosocial.lavender.spl.tech", username: "lavender" },
  { instance: "mastodon.social",              username: "Lavender_Daydream" },
  { instance: "gamerstavern.online",          username: "Lavender_Daydream" },
  { instance: "donphan.social",               username: "Lavender_Daydream" },
  { instance: "blorbo.social",                username: "Lavender_Daydream" },
  { instance: "urusai.social",                username: "Lavender_Daydream" },
];

// Fetches GTS post via RSS feed (no auth needed)
async function fetchGTS(inst, user) {
  const rssUrl = `https://${inst}/@${user}/feed.rss`;
  const res = await fetch(rssUrl);
  if (!res.ok) throw new Error(`RSS fetch failed: ${res.status}`);
  const text = await res.text();

  // Parse the XML response into something JS can read
  const parser = new DOMParser();
  const xml = parser.parseFromString(text, "application/xml");

  const item = xml.querySelector("item");
  if (!item) throw new Error("no posts in RSS feed");

  // Pull the data we need out of the RSS item
  const raw = item.querySelector("description")?.textContent || "";
  const content = raw.replace(/^@\S+\s+posted\s+\d+\s+attachments?:\s*/i, "").replace(/^"|"$/g, "").trim();
  const dateStr  = item.querySelector("pubDate")?.textContent || "";
  const link     = item.querySelector("link")?.textContent || "";

// Grab any image enclosures from the RSS item
  const enclosures = [...item.querySelectorAll("enclosure")]
    .filter(e => e.getAttribute("type")?.startsWith("image/"))
    .map(e => ({
      type: "image",
      url: e.getAttribute("url"),
      preview_url: e.getAttribute("url"),
      description: "",
    }));

  return {
    post: {
      content,
      created_at: new Date(dateStr).toISOString(),
      media_attachments: enclosures,
      url: link,
    },
    instance: inst,
    username: user,
  };
}

// Fetches a post via the standard Mastodon API (for all other instances)
async function fetchAPI(inst, user) {
  const { id } = await fetch(`https://${inst}/api/v1/accounts/lookup?acct=${user}`).then(r => r.json());
  const posts = await fetch(`https://${inst}/api/v1/accounts/${id}/statuses?limit=1&exclude_replies=true&exclude_reblogs=true`).then(r => r.json());
  if (!posts.length) throw new Error("no posts");
  return { post: posts[0], instance: inst, username: user };
}

// Decides which fetch method to use based on the instance
async function fetchLatest(inst, user) {
  if (inst === "gotosocial.lavender.spl.tech") return fetchGTS(inst, user);
  return fetchAPI(inst, user);
}

async function loadStatus() {
  const results = await Promise.allSettled(ACCOUNTS.map(a => fetchLatest(a.instance, a.username)));

  let newest = null;
  results.forEach(r => {
    if (r.status !== 'fulfilled') return;
    if (!newest || new Date(r.value.post.created_at) > new Date(newest.post.created_at)) newest = r.value;
  });

  if (!newest) {
    document.getElementById('fedi-status').textContent = "couldn't load latest post.";
    return;
  }

  // Post text
  const tmp = document.createElement('div');
  tmp.innerHTML = newest.post.content;
  document.getElementById('fedi-status').textContent = tmp.textContent;

  // Meta line: @user@instance · date
  const date = new Date(newest.post.created_at).toLocaleString();
  const profileUrl = `https://${newest.instance}/@${newest.username}`;
  const link = document.createElement('a');
  link.href = profileUrl;
  link.textContent = `@${newest.username}@${newest.instance}`;
  link.target = '_blank';
  const meta = document.getElementById('fedi-meta');
  meta.textContent = '';
  meta.appendChild(link);
  meta.append(` · ${date}`);

  // Images (API only — RSS doesn't provide these)
  const imageContainer = document.getElementById('fedi-images');
  imageContainer.innerHTML = '';
  const images = (newest.post.media_attachments || []).filter(m => m.type === 'image');
  for (const img of images) {
    const a = document.createElement('a');
    a.href = img.url;
    a.target = '_blank';
    a.rel = 'noopener noreferrer';
    const el = document.createElement('img');
    el.src = img.preview_url;
    el.alt = img.description || 'attached image';
    a.appendChild(el);
    imageContainer.appendChild(a);
  }
}

loadStatus();